 You can use  TAB to trigger auto-complete.  Ctrl+C to cancel the input and Ctrl+Q/ Enter to execute the query.
       gq  &lt;endpoint &gt; \ -v   &#39;name=hasura &#39; \ -q   &#39;mutation ($name: String) { table (objects: [{ name: $name }]) } &#39;
            -n, --name=name: name of the graphql definition to execute, use only if there are multiple definitions
   const  { query  }  =  require ( &#39;graphqurl&#39; ) ; function  successCallback ( response ,  queryType ,  parsedQuery )  {  if  ( queryType  ===  &#39;subscription&#39; )  {  // handle subscription response  }  else  {  // handle query/mutation response  } } function  errorCallback ( error ,  queryType ,  parsedQuery )  {  console . error ( error ) ; } query (  {  query:  &#39;query { table { column } }&#39; ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;x-access-key&#39;:  &#39;mysecretxxx&#39; ,  }  } ,  successCallback ,  errorCallback ) ;
   const  { query  }  =  require ( &#39;graphqurl&#39; ) ; query (  {  query:  &#39;query { table { column } }&#39; ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;x-access-key&#39;:  &#39;mysecretxxx&#39; ,  }  } ) . then ( ( response )  =&gt;  console . log ( response ) )  . catch ( ( error )  =&gt;  console . error ( error ) ) ;
  const  { query  }  =  require ( &#39;graphqurl&#39; ) ; query (  {  query:  &#39;subscription { table { column } }&#39; ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;x-access-key&#39;:  &#39;mysecretxxx&#39; ,  }  } ) . then ( ( observable )  =&gt;  {  observable . subscribe (  ( event )  =&gt;  {  console . log ( &#39;Event received: &#39; ,  event ) ;  // handle event  } ,  ( error )  =&gt;  {  console . log ( &#39;Error: &#39; ,  error ) ;  // handle error  }  ) } )  . catch ( ( error )  =&gt;  console . error ( error ) ) ;
    successCallback: [Function] Success callback which is called after a successful response. It is called with the following parameters:
 errorCallback: [Function] Error callback which is called after the occurrence of an error. It is called with the following parameters:
 Returns: [Promise (response) ]If  successCallback and  errorCallback are not provided, this function returns the response wrapped in a promise. response: response is a GraphQL compliant JSON object in case of  queries and  mutations. However, if you make a subscription, it returns an observable that you can later subscribe to. Check  this example to see how to subscribe to observables.
     const  { query  }  =  require ( &#39;graphqurl&#39; ) ; query (  {  query:  `  query ($name: String) {  table(where: { column: $name }) {  id  column  }  }  ` ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;x-access-key&#39;:  &#39;mysecretxxx&#39; ,  } ,  variables:  {  name:  &#39;Alice&#39;  }  } ) . then ( ( response )  =&gt;  console . log ( response ) )  . catch ( ( error )  =&gt;  console . error ( error ) ) ;
  const  { query  }  =  require ( &#39;graphqurl&#39; ) ; query (  {  query:  `  mutation ($id_insert_input: String!, $column_insert_input: String!) {  insert_to_table (  id: $id_insert_input,  column: $column_insert_input  ) {  affected_rows  }  }  ` ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;x-access-key&#39;:  &#39;mysecretxxx&#39; ,  } ,  variables:  {  id_insert_input:  &#39;id_ak23sdfkjk2&#39; ,  column_insert_input:  &#39;Bob&#39;  }  } ) . then ( ( response )  =&gt;  console . log ( response ) )  . catch ( ( error )  =&gt;  console . error ( error ) ) ;
   const  { query  }  =  require ( &#39;graphqurl&#39; ) ; const  eventCallback  =  ( event )  =&gt;  {  console . log ( &#39;Event received:&#39; ,  event ) ;  // handle event } ; const  errorCallback  =  ( error )  =&gt;  {  console . log ( &#39;Error:&#39; ,  error ) } ; query (  {  query:  &#39;subscription { table { column } }&#39; ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;Authorization&#39;:  &#39;Bearer Andkw23kj=Kjsdk2902ksdjfkd&#39;  }  } , ) . then ( ( observable )  =&gt;  {  observable . subscribe (  ( event )  =&gt;  {  console . log ( &#39;Event received&#39; ,  event ) ;  // handle event  } ,  ( error )  =&gt;  {  console . log ( &#39;Error&#39; ,  error ) ;  // handle error  }  ) } ) . catch ( errorCallback ) ;
  const  { query  }  =  require ( &#39;graphqurl&#39; ) ; function  eventCallback ( event )  {  console . log ( &#39;Event received:&#39; ,  event ) ;  // handle event } function  errorCallback ( error )  {  console . log ( &#39;Error:&#39; ,  error ) } query (  {  query:  &#39;subscription { table { column } }&#39; ,  endpoint:  &#39;https://my-graphql-endpoint/graphql&#39; ,  headers:  {  &#39;Authorization&#39;:  &#39;Bearer Andkw23kj=Kjsdk2902ksdjfkd&#39;  }  } ,  eventCallback ,  errorCallback ) ;
